import TagCard from "./TagCard";

function CourseCard({Text}) {
  return (
    <div className="course-card">
      <img/>
      <div style={{display:"flex", flexDirection:"column", paddingRight:"6rem", position:"relative"}}>
      <h3>NameCourse</h3>
        <span>Description</span>
        <ul>
          <li style={{listStyleType:"none"}}> 
            <TagCard Text={"Web"}/>
          </li>
        </ul>
        <div style={{position:"absolute",  insetBlockEnd:"0", textAlign:"end"}}>
          <span>Price</span>
        </div>
      </div>
    </div>
  );
}

export default CourseCard;
